exercises.solution:
function routeMatch(pattern, key) {
  const parts = pattern.split('.');
  const keyParts = key.split('.');
  function match(pi, ki) {
    if (pi === parts.length && ki === keyParts.length) return true;
    if (pi === parts.length) return false;
    if (parts[pi] === '#') {
      for (let j = ki; j <= keyParts.length; j++) {
        if (match(pi + 1, j)) return true;
      }
      return false;
    }
    if (ki === keyParts.length) return false;
    if (parts[pi] === '*' || parts[pi] === keyParts[ki]) return match(pi + 1, ki + 1);
    return false;
  }
  return match(0, 0);
}

