exercises.solution:
async function runSaga(steps, context) {
  const completed = [];
  for (const step of steps) {
    try {
      await step.execute(context);
      completed.push(step);
    } catch (err) {
      for (let i = completed.length - 1; i >= 0; i--) {
        await completed[i].compensate(context);
      }
      throw err;
    }
  }
}

