exercises.tests:
check('first call executes fn', async () => {
  let calls = 0;
  const store = new Map();
  const wrapped = makeIdempotent({ get: k => store.get(k), set: (k,v) => store.set(k,v) }, async (key, amount) => { calls++; return { charged: amount }; });
  const result = await wrapped('key-1', 99);
  expect(result).toEqual({ charged: 99 });
  expect(calls).toBe(1);
});
check('second call with same key skips fn', async () => {
  let calls = 0;
  const store = new Map();
  const wrapped = makeIdempotent({ get: k => store.get(k), set: (k,v) => store.set(k,v) }, async (key, amount) => { calls++; return { charged: amount }; });
  await wrapped('key-2', 50);
  const result = await wrapped('key-2', 50);
  expect(calls).toBe(1);
  expect(result).toEqual({ charged: 50 });
});
check('different keys both execute fn', async () => {
  let calls = 0;
  const store = new Map();
  const wrapped = makeIdempotent({ get: k => store.get(k), set: (k,v) => store.set(k,v) }, async (key) => { calls++; return calls; });
  await wrapped('a');
  await wrapped('b');
  expect(calls).toBe(2);
});

exercises.solution:
function makeIdempotent(store, fn) {
  return async function(key, ...args) {
    const cached = await store.get(key);
    if (cached !== undefined) return cached;
    const result = await fn(key, ...args);
    await store.set(key, result);
    return result;
  };
}

