exercises.solution:
function zScore(value, mean, std) {
  return (value - mean) / std;
}

function featureAblation(features, baseline, scorer) {
  const fullScore = scorer(features);
  return Object.keys(features)
    .map(name => {
      const ablated = { ...features, [name]: baseline[name] };
      const drop = Math.abs(fullScore - scorer(ablated));
      return { feature: name, contribution: drop };
    })
    .sort((a, b) => b.contribution - a.contribution);
}

