exercises.solution:
function minMaxCalibrate(scores) {
  const min = Math.min(...scores);
  const max = Math.max(...scores);
  return function calibrate(score) {
    if (max === min) return 0;
    return (score - min) / (max - min);
  };
}

function topDriver(features, baseline, scorer) {
  const fullScore = scorer(features);
  let best = null;
  let bestDrop = -Infinity;
  for (const name of Object.keys(features)) {
    const ablated = { ...features, [name]: baseline[name] };
    const drop = Math.abs(fullScore - scorer(ablated));
    if (drop > bestDrop) { bestDrop = drop; best = name; }
  }
  return best;
}

exercises.starter:
function makeTokenBucket(capacity, refillRate) {
  // capacity: max tokens per client
  // refillRate: tokens added per millisecond
  // returns { consume(clientId, nowMs?) }
}

exercises.tests:
check('allows up to capacity requests', () => {
  const bucket = makeTokenBucket(3, 0);
  expect(bucket.consume('a', 0)).toBe(true);
  expect(bucket.consume('a', 0)).toBe(true);
  expect(bucket.consume('a', 0)).toBe(true);
  expect(bucket.consume('a', 0)).toBe(false);
});
check('different clients independent', () => {
  const bucket = makeTokenBucket(2, 0);
  expect(bucket.consume('x', 0)).toBe(true);
  expect(bucket.consume('x', 0)).toBe(true);
  expect(bucket.consume('x', 0)).toBe(false);
  expect(bucket.consume('y', 0)).toBe(true);
});
check('tokens refill over time', () => {
  const bucket = makeTokenBucket(2, 1);
  bucket.consume('b', 0);
  bucket.consume('b', 0);
  expect(bucket.consume('b', 0)).toBe(false);
  expect(bucket.consume('b', 1500)).toBe(true);
});

exercises.solution:
function makeTokenBucket(capacity, refillRate) {
  const buckets = new Map();
  return {
    consume(clientId, nowMs = Date.now()) {
      if (!buckets.has(clientId)) {
        buckets.set(clientId, { tokens: capacity, lastMs: nowMs });
      }
      const b = buckets.get(clientId);
      const elapsed = Math.max(0, nowMs - b.lastMs);
      b.tokens = Math.min(capacity, b.tokens + elapsed * refillRate);
      b.lastMs = nowMs;
      if (b.tokens >= 1) {
        b.tokens -= 1;
        return true;
      }
      return false;
    }
  };
}
